import xml.etree.ElementTree as ET
from xml.dom import minidom
import os
from typing import Optional, Dict, Any, Union
from io import BytesIO, StringIO


def validate_and_read_xml(
    file_input: Union[str, bytes, BytesIO],
    schema_file: Optional[str] = None,
    max_size_mb: float = 10.0,
    encoding: str = 'utf-8'
) -> Dict[str, Any]:
    """
    Reads and validates an XML document uploaded by a user.
    
    Args:
        file_input: Path to XML file, XML string, bytes, or file-like object
        schema_file: Optional path to XSD schema file for validation
        max_size_mb: Maximum allowed file size in megabytes
        encoding: Character encoding for the XML file
    
    Returns:
        Dictionary containing:
            - 'valid': Boolean indicating if XML is valid
            - 'root': Root element of the XML tree (if valid)
            - 'tree': ElementTree object (if valid)
            - 'errors': List of error messages (if invalid)
            - 'warnings': List of warning messages
            - 'metadata': Dictionary with XML metadata
    """
    
    result = {
        'valid': False,
        'root': None,
        'tree': None,
        'errors': [],
        'warnings': [],
        'metadata': {}
    }
    
    try:
        # Handle different input types
        if isinstance(file_input, str):
            if os.path.isfile(file_input):
                # File path
                file_size = os.path.getsize(file_input)
                if file_size > max_size_mb * 1024 * 1024:
                    result['errors'].append(f"File size ({file_size / 1024 / 1024:.2f} MB) exceeds maximum allowed size ({max_size_mb} MB)")
                    return result
                
                with open(file_input, 'rb') as f:
                    xml_content = f.read()
            else:
                # XML string
                xml_content = file_input.encode(encoding)
        elif isinstance(file_input, bytes):
            xml_content = file_input
        elif isinstance(file_input, BytesIO):
            xml_content = file_input.read()
            file_input.seek(0)
        else:
            result['errors'].append(f"Unsupported input type: {type(file_input)}")
            return result
        
        # Check size
        if len(xml_content) > max_size_mb * 1024 * 1024:
            result['errors'].append(f"Content size exceeds maximum allowed size ({max_size_mb} MB)")
            return result
        
        # Check for common XML issues
        if not xml_content.strip():
            result['errors'].append("Empty XML content")
            return result
        
        # Check for XML declaration
        xml_str = xml_content.decode(encoding, errors='replace')
        if not xml_str.strip().startswith('<?xml') and not xml_str.strip().startswith('<'):
            result['errors'].append("Content does not appear to be valid XML")
            return result
        
        # Parse XML
        try:
            tree = ET.ElementTree(ET.fromstring(xml_content))
            root = tree.getroot()
        except ET.ParseError as e:
            result['errors'].append(f"XML parsing error: {str(e)}")
            return result
        
        # Collect metadata
        result['metadata']['root_tag'] = root.tag
        result['metadata']['root_attributes'] = dict(root.attrib)
        result['metadata']['encoding'] = encoding
        result['metadata']['size_bytes'] = len(xml_content)
        
        # Count elements
        element_count = len(list(root.iter()))
        result['metadata']['element_count'] = element_count
        
        # Check for namespace
        if '}' in root.tag:
            namespace = root.tag.split('}')[0].strip('{')
            result['metadata']['namespace'] = namespace
        
        # Validate against schema if provided
        if schema_file:
            try:
                from lxml import etree as lxml_etree
                
                if not os.path.isfile(schema_file):
                    result['warnings'].append(f"Schema file not found: {schema_file}")
                else:
                    with open(schema_file, 'rb') as schema_f:
                        schema_root = lxml_etree.XML(schema_f.read())
                        schema = lxml_etree.XMLSchema(schema_root)
                    
                    xml_doc = lxml_etree.XML(xml_content)
                    
                    if not schema.validate(xml_doc):
                        result['errors'].append("XML does not conform to schema")
                        for error in schema.error_log:
                            result['errors'].append(f"Line {error.line}: {error.message}")
                        return result
                    
                    result['metadata']['schema_validated'] = True
            except ImportError:
                result['warnings'].append("lxml not available for schema validation")
            except Exception as e:
                result['errors'].append(f"Schema validation error: {str(e)}")
                return result
        
        # Check for well-formedness issues
        try:
            minidom.parseString(xml_content)
        except Exception as e:
            result['warnings'].append(f"Well-formedness check warning: {str(e)}")
        
        # All validations passed
        result['valid'] = True
        result['root'] = root
        result['tree'] = tree
        
    except Exception as e:
        result['errors'].append(f"Unexpected error: {str(e)}")
    
    return result


def extract_xml_data(root: ET.Element, path: Optional[str] = None) -> Any:
    """
    Extract data from XML element using XPath-like path.
    
    Args:
        root: Root element of XML tree
        path: Optional path to specific element(s)
    
    Returns:
        Element, list of elements, or text content
    """
    if path is None:
        return root
    
    elements = root.findall(path)
    if len(elements) == 0:
        return None
    elif len(elements) == 1:
        return elements[0]
    else:
        return elements


def xml_to_dict(element: ET.Element) -> Dict[str, Any]:
    """
    Convert XML element to dictionary.
    
    Args:
        element: XML element to convert
    
    Returns:
        Dictionary representation of XML
    """
    result = {}
    
    # Add attributes
    if element.attrib:
        result['@attributes'] = dict(element.attrib)
    
    # Add text content
    if element.text and element.text.strip():
        result['#text'] = element.text.strip()
    
    # Add child elements
    for child in element:
        child_data = xml_to_dict(child)
        
        if child.tag in result:
            # Multiple elements with same tag
            if not isinstance(result[child.tag], list):
                result[child.tag] = [result[child.tag]]
            result[child.tag].append(child_data)
        else:
            result[child.tag] = child_data
    
    return result if result else (element.text or '')